/**
 * Notification model — core types for the notification system.
 *
 * Architecture: All notifications flow through the EventBus. When a domain
 * event occurs (e.g., order:created), the NotificationService listens for it,
 * constructs a NotificationPayload, and dispatches it to the appropriate
 * NotificationAdapter(s) based on channel.
 *
 * Type hierarchy:
 * - NotificationType: What happened (e.g., order_confirmation)
 * - NotificationChannel: How to deliver (e.g., email, sms)
 * - NotificationPayload: What to send (constructed by NotificationService)
 * - NotificationRecord: What's stored (includes delivery status)
 * - NotificationResult: What adapters return (success/failure)
 */

/**
 * The kind of notification being sent. Maps to a domain event.
 * Extend this union as new notification-worthy events are added.
 */
export type NotificationType =
  | 'order_confirmation'
  | 'order_status_update'
  | 'welcome'
  | 'account_updated';

/**
 * Delivery channel for a notification.
 * Each channel has a corresponding adapter that implements NotificationAdapter.
 */
export type NotificationChannel = 'email' | 'sms' | 'webhook' | 'in_app';

/**
 * Priority level for notification delivery.
 * Adapters may use this to determine delivery urgency.
 */
export type NotificationPriority = 'low' | 'normal' | 'high' | 'urgent';

/**
 * Delivery status of a notification.
 */
export type NotificationStatus = 'pending' | 'sent' | 'failed';

/**
 * Payload describing a notification to be sent.
 * Constructed by the NotificationService from domain events,
 * then passed to adapters for delivery.
 */
export interface NotificationPayload {
  /** What kind of notification this is. */
  type: NotificationType;
  /** Who receives the notification (email, phone, user ID, etc.). */
  recipient: string;
  /** Subject line or title. */
  subject: string;
  /** Notification body content. */
  body: string;
  /** Which channel to deliver through. */
  channel: NotificationChannel;
  /** Delivery priority. Defaults to 'normal' if omitted. */
  priority: NotificationPriority;
  /** Optional key-value metadata for adapter-specific data. */
  metadata?: Record<string, unknown>;
}

/**
 * A stored notification record with delivery status tracking.
 * Created by NotificationService after dispatching to an adapter.
 */
export interface NotificationRecord {
  /** Unique notification ID (e.g., notif-0001). */
  id: string;
  /** The notification type. */
  type: NotificationType;
  /** The delivery channel used. */
  channel: NotificationChannel;
  /** Recipient identifier. */
  recipient: string;
  /** Subject line. */
  subject: string;
  /** Body content. */
  body: string;
  /** Current delivery status. */
  status: NotificationStatus;
  /** Delivery priority. */
  priority: NotificationPriority;
  /** Optional metadata carried from the payload. */
  metadata?: Record<string, unknown>;
  /** When the notification record was created. */
  createdAt: Date;
  /** When the notification was successfully sent (if status is 'sent'). */
  sentAt?: Date;
  /** Reason for failure (if status is 'failed'). */
  failureReason?: string;
}

/**
 * Result returned by a NotificationAdapter after attempting delivery.
 */
export interface NotificationResult {
  /** Whether delivery succeeded. */
  success: boolean;
  /** The notification ID this result pertains to. */
  notificationId: string;
  /** The channel that attempted delivery. */
  channel: NotificationChannel;
  /** Reason for failure, if success is false. */
  failureReason?: string;
}

/**
 * Input for creating a notification payload.
 * Used by event handlers to build payloads without specifying all fields.
 */
export interface CreateNotificationInput {
  type: NotificationType;
  recipient: string;
  subject: string;
  body: string;
  channel?: NotificationChannel;
  priority?: NotificationPriority;
  metadata?: Record<string, unknown>;
}

/**
 * Event type definitions for the event-driven notification system.
 *
 * This application uses an event bus for decoupled communication between
 * modules. Services emit events when significant actions occur, and
 * interested listeners handle them independently.
 *
 * Event categories:
 * - order:*  — Order lifecycle events (emitted by OrderService)
 * - user:*   — User lifecycle events (emitted by UserService)
 * - notification:* — Notification delivery events (emitted by NotificationService)
 *
 * ALL cross-service communication MUST go through the EventBus.
 * Do not use direct callbacks or shared mutable state between services.
 */

import type { Order } from '../models/order.js';
import type { User } from '../models/user.js';
import type { NotificationRecord } from '../models/notification.js';

// --- Order Events ---

export interface OrderCreatedEvent {
  type: 'order:created';
  order: Order;
  user: User;
  timestamp: Date;
}

export interface OrderStatusChangedEvent {
  type: 'order:status-changed';
  order: Order;
  previousStatus: string;
  newStatus: string;
  timestamp: Date;
}

// --- User Events ---

export interface UserCreatedEvent {
  type: 'user:created';
  user: User;
  timestamp: Date;
}

export interface UserUpdatedEvent {
  type: 'user:updated';
  user: User;
  changes: string[];
  timestamp: Date;
}

// --- Notification Lifecycle Events ---

export interface NotificationSentEvent {
  type: 'notification:sent';
  notification: NotificationRecord;
  timestamp: Date;
}

export interface NotificationFailedEvent {
  type: 'notification:failed';
  notification: NotificationRecord;
  reason: string;
  timestamp: Date;
}

// --- Union Types ---

export type AppEvent =
  | OrderCreatedEvent
  | OrderStatusChangedEvent
  | UserCreatedEvent
  | UserUpdatedEvent
  | NotificationSentEvent
  | NotificationFailedEvent;

export type EventType = AppEvent['type'];

/**
 * Base interface for all notification adapters.
 *
 * CONSTRAINT: Every notification delivery channel (email, SMS, webhook, in-app)
 * MUST implement this interface. The NotificationService dispatches payloads
 * to adapters based on the `channel` property.
 *
 * Adapter contract:
 * 1. `channel` must match exactly one NotificationChannel value.
 * 2. `send()` must be async and return a NotificationResult.
 * 3. `send()` must NOT throw — return { success: false, failureReason } instead.
 * 4. Adapters are stateless; they do not store notifications.
 * 5. Adapters receive their configuration via constructor injection.
 *
 * Example implementation:
 * ```typescript
 * class EmailAdapter implements NotificationAdapter {
 *   readonly channel: NotificationChannel = 'email';
 *   async send(payload: NotificationPayload): Promise<NotificationResult> {
 *     // ... send email ...
 *     return { success: true, notificationId: payload.subject, channel: 'email' };
 *   }
 * }
 * ```
 */

import type {
  NotificationChannel,
  NotificationPayload,
  NotificationResult,
} from '../models/notification.js';

/**
 * Interface that all notification delivery adapters must implement.
 */
export interface NotificationAdapter {
  /** The delivery channel this adapter handles. Must be unique per adapter. */
  readonly channel: NotificationChannel;

  /**
   * Attempt to deliver a notification.
   *
   * @param payload - The notification payload to deliver.
   * @returns A result indicating success or failure. Must not throw.
   */
  send(payload: NotificationPayload): Promise<NotificationResult>;
}

/**
 * Email notification adapter — delivers notifications via email.
 *
 * This is a stub implementation that logs email delivery instead of
 * actually sending. In production, replace the `deliverEmail` method
 * with a real SMTP client or email API integration (e.g., SendGrid, SES).
 *
 * Implements the NotificationAdapter interface. Registered with the
 * NotificationService to handle all notifications on the 'email' channel.
 *
 * Configuration is injected via constructor to support different
 * environments (dev, staging, production).
 */

import type { NotificationAdapter } from './notification.adapter.js';
import type {
  NotificationChannel,
  NotificationPayload,
  NotificationResult,
} from '../models/notification.js';
import { Logger } from '../utils/logger.js';

/**
 * Configuration for the email adapter.
 */
export interface EmailAdapterConfig {
  /** SMTP host or email API endpoint. */
  host: string;
  /** SMTP port (e.g., 587 for TLS). */
  port: number;
  /** Sender email address for the "From" field. */
  fromAddress: string;
  /** Whether this is a stub (logs instead of sending). */
  stubMode: boolean;
}

/**
 * Default configuration for development/testing.
 */
export const defaultEmailConfig: EmailAdapterConfig = {
  host: 'localhost',
  port: 587,
  fromAddress: 'noreply@taskflow.dev',
  stubMode: true,
};

/**
 * Email notification adapter.
 *
 * Sends notifications via email. In stub mode (default), logs the
 * email details instead of actually delivering.
 */
export class EmailAdapter implements NotificationAdapter {
  readonly channel: NotificationChannel = 'email';

  private logger = new Logger('EmailAdapter');
  private config: EmailAdapterConfig;
  private sentEmails: Array<{
    to: string;
    from: string;
    subject: string;
    body: string;
    sentAt: Date;
  }> = [];

  constructor(config?: Partial<EmailAdapterConfig>) {
    this.config = { ...defaultEmailConfig, ...config };
  }

  /**
   * Send a notification via email.
   *
   * In stub mode, logs the email and records it in memory.
   * In production mode, would delegate to an SMTP client.
   *
   * @param payload - The notification payload to deliver via email.
   * @returns Result indicating success or failure. Never throws.
   */
  async send(payload: NotificationPayload): Promise<NotificationResult> {
    const result: NotificationResult = {
      success: false,
      notificationId: '',
      channel: 'email',
    };

    try {
      if (this.config.stubMode) {
        // Stub mode: log instead of sending
        this.logger.info(
          `[STUB] Email to ${payload.recipient}: "${payload.subject}"`,
        );
        this.sentEmails.push({
          to: payload.recipient,
          from: this.config.fromAddress,
          subject: payload.subject,
          body: payload.body,
          sentAt: new Date(),
        });
      } else {
        // Production mode: delegate to real email delivery
        await this.deliverEmail(payload);
      }

      result.success = true;
      this.logger.info(`Email sent to ${payload.recipient}`);
    } catch (error) {
      const message = error instanceof Error ? error.message : 'Unknown email delivery error';
      result.success = false;
      result.failureReason = message;
      this.logger.error(`Email delivery failed for ${payload.recipient}: ${message}`);
    }

    return result;
  }

  /**
   * Get all emails sent in stub mode. Useful for testing.
   */
  getSentEmails(): Array<{
    to: string;
    from: string;
    subject: string;
    body: string;
    sentAt: Date;
  }> {
    return [...this.sentEmails];
  }

  /**
   * Clear sent email records. Useful for testing.
   */
  clearSentEmails(): void {
    this.sentEmails = [];
  }

  /**
   * Get the current adapter configuration.
   */
  getConfig(): Readonly<EmailAdapterConfig> {
    return { ...this.config };
  }

  /**
   * Real email delivery — override in production or replace with actual SMTP/API.
   *
   * @param _payload - The notification payload (unused in stub).
   * @throws Error if delivery fails.
   */
  private async deliverEmail(_payload: NotificationPayload): Promise<void> {
    // TODO: Replace with real SMTP client or email API integration.
    // Example integrations:
    //   - nodemailer for SMTP
    //   - @sendgrid/mail for SendGrid
    //   - @aws-sdk/client-ses for Amazon SES
    throw new Error(
      'Real email delivery not implemented. Set stubMode: true for development.',
    );
  }
}

/**
 * Notification service — orchestrates notification delivery in response to domain events.
 *
 * ARCHITECTURE DECISION: Event-Driven with Adapter Dispatch
 * =========================================================
 * This service uses the EventBus exclusively for receiving domain events.
 * ALL cross-service communication flows through EventBus — no direct callbacks,
 * no shared mutable state, no CallbackRegistry.
 *
 * Flow:
 * 1. A domain service (OrderService, UserService) emits an event via EventBus.
 * 2. NotificationService listens for relevant events.
 * 3. Event handlers map domain events → NotificationPayload(s).
 * 4. Payloads are dispatched to the appropriate NotificationAdapter by channel.
 * 5. Delivery results are recorded as NotificationRecords.
 * 6. notification:sent / notification:failed events are emitted for observability.
 *
 * CONSTRAINTS:
 * - All adapters MUST implement the NotificationAdapter interface.
 * - All domain events MUST flow through EventBus.emit().
 * - Adapters MUST NOT throw from send() — return { success: false } instead.
 * - This service owns the notification lifecycle; adapters own delivery mechanics.
 *
 * Depends on:
 * - EventBus (event system) for receiving ALL domain events
 * - NotificationAdapter implementations for delivery
 */

import type { EventBus } from '../events/event-bus.js';
import type {
  OrderCreatedEvent,
  OrderStatusChangedEvent,
  UserCreatedEvent,
  UserUpdatedEvent,
} from '../events/event-types.js';
import type { NotificationAdapter } from '../adapters/notification.adapter.js';
import type {
  NotificationChannel,
  NotificationPayload,
  NotificationRecord,
  NotificationResult,
  CreateNotificationInput,
} from '../models/notification.js';
import { Logger } from '../utils/logger.js';

let nextId = 1;

function generateNotificationId(): string {
  return `notif-${String(nextId++).padStart(4, '0')}`;
}

/** Reset the ID counter. Used in tests. */
export function resetNotificationIdCounter(): void {
  nextId = 1;
}

export class NotificationService {
  private logger = new Logger('NotificationService');
  private notifications: NotificationRecord[] = [];
  private adapters: Map<NotificationChannel, NotificationAdapter> = new Map();

  constructor(private eventBus: EventBus) {
    this.registerEventHandlers();
  }

  // ---------------------------------------------------------------------------
  // Adapter Registration
  // ---------------------------------------------------------------------------

  /**
   * Register a notification adapter for a delivery channel.
   *
   * Only one adapter per channel is allowed. Registering a second adapter
   * for the same channel replaces the previous one.
   *
   * @param adapter - The adapter to register. Must implement NotificationAdapter.
   */
  registerAdapter(adapter: NotificationAdapter): void {
    this.logger.info(`Registering adapter for channel: ${adapter.channel}`);
    this.adapters.set(adapter.channel, adapter);
  }

  /**
   * Unregister the adapter for a delivery channel.
   *
   * @param channel - The channel whose adapter to remove.
   * @returns true if an adapter was removed, false if none was registered.
   */
  unregisterAdapter(channel: NotificationChannel): boolean {
    this.logger.info(`Unregistering adapter for channel: ${channel}`);
    return this.adapters.delete(channel);
  }

  /**
   * Get all registered adapter channels.
   */
  getRegisteredChannels(): NotificationChannel[] {
    return Array.from(this.adapters.keys());
  }

  // ---------------------------------------------------------------------------
  // Notification Dispatch
  // ---------------------------------------------------------------------------

  /**
   * Send a notification through the appropriate adapter.
   *
   * This is the core dispatch method. It:
   * 1. Builds a NotificationRecord from the input.
   * 2. Looks up the adapter for the specified channel.
   * 3. Calls adapter.send() and records the result.
   * 4. Emits notification:sent or notification:failed events.
   *
   * @param input - Notification details. Channel defaults to 'email'.
   * @returns The created NotificationRecord with delivery status.
   */
  async send(input: CreateNotificationInput): Promise<NotificationRecord> {
    const channel = input.channel ?? 'email';
    const priority = input.priority ?? 'normal';

    const payload: NotificationPayload = {
      type: input.type,
      recipient: input.recipient,
      subject: input.subject,
      body: input.body,
      channel,
      priority,
      metadata: input.metadata,
    };

    const record: NotificationRecord = {
      id: generateNotificationId(),
      type: input.type,
      channel,
      recipient: input.recipient,
      subject: input.subject,
      body: input.body,
      status: 'pending',
      priority,
      metadata: input.metadata,
      createdAt: new Date(),
    };

    const adapter = this.adapters.get(channel);
    if (!adapter) {
      record.status = 'failed';
      record.failureReason = `No adapter registered for channel: ${channel}`;
      this.logger.warn(record.failureReason);
      this.notifications.push(record);

      await this.eventBus.emit({
        type: 'notification:failed',
        notification: record,
        reason: record.failureReason,
        timestamp: new Date(),
      });

      return record;
    }

    // Dispatch to the adapter
    let result: NotificationResult;
    try {
      result = await adapter.send(payload);
    } catch (error) {
      // Adapters should not throw, but handle it gracefully if they do
      const reason = error instanceof Error ? error.message : 'Unknown adapter error';
      result = {
        success: false,
        notificationId: record.id,
        channel,
        failureReason: reason,
      };
    }

    // Update record based on result
    result.notificationId = record.id;
    if (result.success) {
      record.status = 'sent';
      record.sentAt = new Date();
    } else {
      record.status = 'failed';
      record.failureReason = result.failureReason;
    }

    this.notifications.push(record);

    // Emit lifecycle event
    if (record.status === 'sent') {
      await this.eventBus.emit({
        type: 'notification:sent',
        notification: record,
        timestamp: new Date(),
      });
    } else {
      await this.eventBus.emit({
        type: 'notification:failed',
        notification: record,
        reason: record.failureReason ?? 'Unknown error',
        timestamp: new Date(),
      });
    }

    this.logger.info(
      `Notification ${record.id} ${record.status} via ${channel} to ${record.recipient}`,
    );

    return record;
  }

  // ---------------------------------------------------------------------------
  // Event Handlers — Map domain events to notifications
  // ---------------------------------------------------------------------------

  /**
   * Register event handlers for all notification-worthy domain events.
   *
   * IMPORTANT: ALL event subscriptions go through EventBus.on().
   * Do NOT use CallbackRegistry or direct callbacks.
   */
  private registerEventHandlers(): void {
    this.eventBus.on<OrderCreatedEvent>('order:created', (event) => {
      return this.handleOrderCreated(event);
    });

    this.eventBus.on<OrderStatusChangedEvent>('order:status-changed', (event) => {
      return this.handleOrderStatusChanged(event);
    });

    this.eventBus.on<UserCreatedEvent>('user:created', (event) => {
      return this.handleUserCreated(event);
    });

    this.eventBus.on<UserUpdatedEvent>('user:updated', (event) => {
      return this.handleUserUpdated(event);
    });
  }

  /**
   * Handle order created — send confirmation email to the ordering user.
   */
  private async handleOrderCreated(event: OrderCreatedEvent): Promise<void> {
    this.logger.info(`Handling order:created for order ${event.order.id}`);

    const itemSummary = event.order.items
      .map((item) => `${item.name} x${item.quantity}`)
      .join(', ');

    await this.send({
      type: 'order_confirmation',
      recipient: event.user.email,
      subject: `Order Confirmation: ${event.order.id}`,
      body: `Your order has been placed. Items: ${itemSummary}. Total: $${event.order.total.toFixed(2)}`,
      channel: 'email',
      priority: 'normal',
    });
  }

  /**
   * Handle order status change — notify user of the update.
   */
  private async handleOrderStatusChanged(event: OrderStatusChangedEvent): Promise<void> {
    this.logger.info(
      `Handling order:status-changed for order ${event.order.id}: ${event.previousStatus} -> ${event.newStatus}`,
    );

    await this.send({
      type: 'order_status_update',
      recipient: event.order.userId,
      subject: `Order Update: ${event.order.id}`,
      body: `Your order status has changed from ${event.previousStatus} to ${event.newStatus}.`,
      channel: 'email',
      priority: event.newStatus === 'cancelled' ? 'high' : 'normal',
    });
  }

  /**
   * Handle user created — send welcome notification.
   */
  private async handleUserCreated(event: UserCreatedEvent): Promise<void> {
    this.logger.info(`Handling user:created for user ${event.user.id}`);

    await this.send({
      type: 'welcome',
      recipient: event.user.email,
      subject: 'Welcome to TaskFlow Pro!',
      body: `Hi ${event.user.name}, welcome to TaskFlow Pro. Your account has been created.`,
      channel: 'email',
      priority: 'normal',
    });
  }

  /**
   * Handle user updated — notify user of account changes.
   */
  private async handleUserUpdated(event: UserUpdatedEvent): Promise<void> {
    this.logger.info(`Handling user:updated for user ${event.user.id}`);

    await this.send({
      type: 'account_updated',
      recipient: event.user.email,
      subject: 'Account Updated',
      body: `Your account has been updated. Changed fields: ${event.changes.join(', ')}.`,
      channel: 'email',
      priority: 'low',
    });
  }

  // ---------------------------------------------------------------------------
  // Notification Queries
  // ---------------------------------------------------------------------------

  /**
   * Get all notification records.
   */
  getNotifications(): NotificationRecord[] {
    return [...this.notifications];
  }

  /**
   * Get notifications for a specific recipient.
   */
  getNotificationsForRecipient(recipient: string): NotificationRecord[] {
    return this.notifications.filter((n) => n.recipient === recipient);
  }

  /**
   * Get notifications filtered by status.
   */
  getNotificationsByStatus(status: NotificationRecord['status']): NotificationRecord[] {
    return this.notifications.filter((n) => n.status === status);
  }

  /**
   * Get notifications filtered by type.
   */
  getNotificationsByType(type: NotificationRecord['type']): NotificationRecord[] {
    return this.notifications.filter((n) => n.type === type);
  }

  /**
   * Get the total count of notification records.
   */
  getNotificationCount(): number {
    return this.notifications.length;
  }

  /**
   * Clear all notification records. Useful for testing.
   */
  clearNotifications(): void {
    this.notifications = [];
  }
}

/**
 * Notification service — orchestrates notification delivery in response to domain events.
 *
 * ARCHITECTURE DECISION: Event-Driven with Adapter Dispatch
 * =========================================================
 * This service uses the EventBus exclusively for receiving domain events.
 * ALL cross-service communication flows through EventBus — no direct callbacks,
 * no shared mutable state, no CallbackRegistry.
 *
 * Flow:
 * 1. A domain service (OrderService, UserService) emits an event via EventBus.
 * 2. NotificationService listens for relevant events.
 * 3. Event handlers map domain events → NotificationPayload(s).
 * 4. Payloads are dispatched to the appropriate NotificationAdapter by channel.
 * 5. Delivery results are recorded as NotificationRecords.
 * 6. notification:sent / notification:failed events are emitted for observability.
 *
 * CONSTRAINTS:
 * - All adapters MUST implement the NotificationAdapter interface.
 * - All domain events MUST flow through EventBus.emit().
 * - Adapters MUST NOT throw from send() — return { success: false } instead.
 * - This service owns the notification lifecycle; adapters own delivery mechanics.
 *
 * Depends on:
 * - EventBus (event system) for receiving ALL domain events
 * - NotificationAdapter implementations for delivery
 */

import type { EventBus } from '../events/event-bus.js';
import type {
  OrderCreatedEvent,
  OrderStatusChangedEvent,
  UserCreatedEvent,
  UserUpdatedEvent,
} from '../events/event-types.js';
import type { NotificationAdapter } from '../adapters/notification.adapter.js';
import type {
  NotificationChannel,
  NotificationPayload,
  NotificationRecord,
  NotificationResult,
  CreateNotificationInput,
} from '../models/notification.js';
import { Logger } from '../utils/logger.js';

let nextId = 1;

function generateNotificationId(): string {
  return `notif-${String(nextId++).padStart(4, '0')}`;
}

/** Reset the ID counter. Used in tests. */
export function resetNotificationIdCounter(): void {
  nextId = 1;
}

export class NotificationService {
  private logger = new Logger('NotificationService');
  private notifications: NotificationRecord[] = [];
  private adapters: Map<NotificationChannel, NotificationAdapter> = new Map();

  constructor(private eventBus: EventBus) {
    this.registerEventHandlers();
  }

  // ---------------------------------------------------------------------------
  // Adapter Registration
  // ---------------------------------------------------------------------------

  /**
   * Register a notification adapter for a delivery channel.
   *
   * Only one adapter per channel is allowed. Registering a second adapter
   * for the same channel replaces the previous one.
   *
   * @param adapter - The adapter to register. Must implement NotificationAdapter.
   */
  registerAdapter(adapter: NotificationAdapter): void {
    this.logger.info(`Registering adapter for channel: ${adapter.channel}`);
    this.adapters.set(adapter.channel, adapter);
  }

  /**
   * Unregister the adapter for a delivery channel.
   *
   * @param channel - The channel whose adapter to remove.
   * @returns true if an adapter was removed, false if none was registered.
   */
  unregisterAdapter(channel: NotificationChannel): boolean {
    this.logger.info(`Unregistering adapter for channel: ${channel}`);
    return this.adapters.delete(channel);
  }

  /**
   * Get all registered adapter channels.
   */
  getRegisteredChannels(): NotificationChannel[] {
    return Array.from(this.adapters.keys());
  }

  // ---------------------------------------------------------------------------
  // Notification Dispatch
  // ---------------------------------------------------------------------------

  /**
   * Send a notification through the appropriate adapter.
   *
   * This is the core dispatch method. It:
   * 1. Builds a NotificationRecord from the input.
   * 2. Looks up the adapter for the specified channel.
   * 3. Calls adapter.send() and records the result.
   * 4. Emits notification:sent or notification:failed events.
   *
   * @param input - Notification details. Channel defaults to 'email'.
   * @returns The created NotificationRecord with delivery status.
   */
  async send(input: CreateNotificationInput): Promise<NotificationRecord> {
    const channel = input.channel ?? 'email';
    const priority = input.priority ?? 'normal';

    const payload: NotificationPayload = {
      type: input.type,
      recipient: input.recipient,
      subject: input.subject,
      body: input.body,
      channel,
      priority,
      metadata: input.metadata,
    };

    const record: NotificationRecord = {
      id: generateNotificationId(),
      type: input.type,
      channel,
      recipient: input.recipient,
      subject: input.subject,
      body: input.body,
      status: 'pending',
      priority,
      metadata: input.metadata,
      createdAt: new Date(),
    };

    const adapter = this.adapters.get(channel);
    if (!adapter) {
      record.status = 'failed';
      record.failureReason = `No adapter registered for channel: ${channel}`;
      this.logger.warn(record.failureReason);
      this.notifications.push(record);

      await this.eventBus.emit({
        type: 'notification:failed',
        notification: record,
        reason: record.failureReason,
        timestamp: new Date(),
      });

      return record;
    }

    // Dispatch to the adapter
    let result: NotificationResult;
    try {
      result = await adapter.send(payload);
    } catch (error) {
      // Adapters should not throw, but handle it gracefully if they do
      const reason = error instanceof Error ? error.message : 'Unknown adapter error';
      result = {
        success: false,
        notificationId: record.id,
        channel,
        failureReason: reason,
      };
    }

    // Update record based on result
    result.notificationId = record.id;
    if (result.success) {
      record.status = 'sent';
      record.sentAt = new Date();
    } else {
      record.status = 'failed';
      record.failureReason = result.failureReason;
    }

    this.notifications.push(record);

    // Emit lifecycle event
    if (record.status === 'sent') {
      await this.eventBus.emit({
        type: 'notification:sent',
        notification: record,
        timestamp: new Date(),
      });
    } else {
      await this.eventBus.emit({
        type: 'notification:failed',
        notification: record,
        reason: record.failureReason ?? 'Unknown error',
        timestamp: new Date(),
      });
    }

    this.logger.info(
      `Notification ${record.id} ${record.status} via ${channel} to ${record.recipient}`,
    );

    return record;
  }

  // ---------------------------------------------------------------------------
  // Event Handlers — Map domain events to notifications
  // ---------------------------------------------------------------------------

  /**
   * Register event handlers for all notification-worthy domain events.
   *
   * IMPORTANT: ALL event subscriptions go through EventBus.on().
   * Do NOT use CallbackRegistry or direct callbacks.
   */
  private registerEventHandlers(): void {
    this.eventBus.on<OrderCreatedEvent>('order:created', (event) => {
      return this.handleOrderCreated(event);
    });

    this.eventBus.on<OrderStatusChangedEvent>('order:status-changed', (event) => {
      return this.handleOrderStatusChanged(event);
    });

    this.eventBus.on<UserCreatedEvent>('user:created', (event) => {
      return this.handleUserCreated(event);
    });

    this.eventBus.on<UserUpdatedEvent>('user:updated', (event) => {
      return this.handleUserUpdated(event);
    });
  }

  /**
   * Handle order created — send confirmation email to the ordering user.
   */
  private async handleOrderCreated(event: OrderCreatedEvent): Promise<void> {
    this.logger.info(`Handling order:created for order ${event.order.id}`);

    const itemSummary = event.order.items
      .map((item) => `${item.name} x${item.quantity}`)
      .join(', ');

    await this.send({
      type: 'order_confirmation',
      recipient: event.user.email,
      subject: `Order Confirmation: ${event.order.id}`,
      body: `Your order has been placed. Items: ${itemSummary}. Total: $${event.order.total.toFixed(2)}`,
      channel: 'email',
      priority: 'normal',
    });
  }

  /**
   * Handle order status change — notify user of the update.
   */
  private async handleOrderStatusChanged(event: OrderStatusChangedEvent): Promise<void> {
    this.logger.info(
      `Handling order:status-changed for order ${event.order.id}: ${event.previousStatus} -> ${event.newStatus}`,
    );

    await this.send({
      type: 'order_status_update',
      recipient: event.order.userId,
      subject: `Order Update: ${event.order.id}`,
      body: `Your order status has changed from ${event.previousStatus} to ${event.newStatus}.`,
      channel: 'email',
      priority: event.newStatus === 'cancelled' ? 'high' : 'normal',
    });
  }

  /**
   * Handle user created — send welcome notification.
   */
  private async handleUserCreated(event: UserCreatedEvent): Promise<void> {
    this.logger.info(`Handling user:created for user ${event.user.id}`);

    await this.send({
      type: 'welcome',
      recipient: event.user.email,
      subject: 'Welcome to TaskFlow Pro!',
      body: `Hi ${event.user.name}, welcome to TaskFlow Pro. Your account has been created.`,
      channel: 'email',
      priority: 'normal',
    });
  }

  /**
   * Handle user updated — notify user of account changes.
   */
  private async handleUserUpdated(event: UserUpdatedEvent): Promise<void> {
    this.logger.info(`Handling user:updated for user ${event.user.id}`);

    await this.send({
      type: 'account_updated',
      recipient: event.user.email,
      subject: 'Account Updated',
      body: `Your account has been updated. Changed fields: ${event.changes.join(', ')}.`,
      channel: 'email',
      priority: 'low',
    });
  }

  // ---------------------------------------------------------------------------
  // Notification Queries
  // ---------------------------------------------------------------------------

  /**
   * Get all notification records.
   */
  getNotifications(): NotificationRecord[] {
    return [...this.notifications];
  }

  /**
   * Get notifications for a specific recipient.
   */
  getNotificationsForRecipient(recipient: string): NotificationRecord[] {
    return this.notifications.filter((n) => n.recipient === recipient);
  }

  /**
   * Get notifications filtered by status.
   */
  getNotificationsByStatus(status: NotificationRecord['status']): NotificationRecord[] {
    return this.notifications.filter((n) => n.status === status);
  }

  /**
   * Get notifications filtered by type.
   */
  getNotificationsByType(type: NotificationRecord['type']): NotificationRecord[] {
    return this.notifications.filter((n) => n.type === type);
  }

  /**
   * Get the total count of notification records.
   */
  getNotificationCount(): number {
    return this.notifications.length;
  }

  /**
   * Clear all notification records. Useful for testing.
   */
  clearNotifications(): void {
    this.notifications = [];
  }
}

