parameters.content:
/**
 * TaskFlow Pro — A task and order management system.
 *
 * Architecture:
 * - Service Layer: UserService, OrderService, NotificationService (business logic)
 * - Repository Layer: UserRepository, OrderRepository (data access via Repository pattern)
 * - Adapter Layer: EmailAdapter (notification delivery via Adapter pattern)
 * - Utility Layer: Database, Logger, Pagination (infrastructure)
 * - Event System: EventBus with typed events (decoupled communication)
 *
 * Key architectural decisions:
 * 1. Repository pattern for all data access (no direct DB calls from services)
 * 2. Event-driven notifications: ALL cross-service communication flows through EventBus
 * 3. Adapter pattern for notification delivery: each channel has an adapter
 * 4. Services emit events; NotificationService listens and dispatches to adapters
 */

// Models
export type { User, CreateUserInput, UpdateUserInput } from './models/user.js';
export type {
  Order,
  OrderItem,
  OrderStatus,
  CreateOrderInput,
} from './models/order.js';
export { calculateOrderTotal } from './models/order.js';
export type {
  NotificationType,
  NotificationChannel,
  NotificationPriority,
  NotificationStatus,
  NotificationPayload,
  NotificationRecord,
  NotificationResult,
  CreateNotificationInput,
} from './models/notification.js';

// Utilities
export { Database, getDatabase, resetDatabase } from './utils/database.js';
export { Logger } from './utils/logger.js';
export { paginate } from './utils/pagination.js';
export type { PaginationResult } from './utils/pagination.js';

// Repositories
export { BaseRepository } from './repositories/base.repository.js';
export { UserRepository } from './repositories/user.repository.js';
export { OrderRepository } from './repositories/order.repository.js';

// Events
export { EventBus } from './events/event-bus.js';
export type {
  AppEvent,
  EventType,
  OrderCreatedEvent,
  OrderStatusChangedEvent,
  UserCreatedEvent,
  UserUpdatedEvent,
  NotificationSentEvent,
  NotificationFailedEvent,
} from './events/event-types.js';

// Adapters
export type { NotificationAdapter } from './adapters/notification.adapter.js';
export { EmailAdapter } from './adapters/email.adapter.js';
export type { EmailAdapterConfig } from './adapters/email.adapter.js';
export { defaultEmailConfig } from './adapters/email.adapter.js';

// Services
export { UserService } from './services/user.service.js';
export { OrderService } from './services/order.service.js';
export { NotificationService } from './services/notification.service.js';

// Config
export { createConfig, defaultConfig } from './config/app.config.js';
export type { AppConfig } from './config/app.config.js';

/**
 * TaskFlow Pro — A task and order management system.
 *
 * Architecture:
 * - Service Layer: UserService, OrderService, NotificationService (business logic)
 * - Repository Layer: UserRepository, OrderRepository (data access via Repository pattern)
 * - Adapter Layer: EmailAdapter (notification delivery via Adapter pattern)
 * - Utility Layer: Database, Logger, Pagination (infrastructure)
 * - Event System: EventBus with typed events (decoupled communication)
 *
 * Key architectural decisions:
 * 1. Repository pattern for all data access (no direct DB calls from services)
 * 2. Event-driven notifications: ALL cross-service communication flows through EventBus
 * 3. Adapter pattern for notification delivery: each channel has an adapter
 * 4. Services emit events; NotificationService listens and dispatches to adapters
 */

// Models
export type { User, CreateUserInput, UpdateUserInput } from './models/user.js';
export type {
  Order,
  OrderItem,
  OrderStatus,
  CreateOrderInput,
} from './models/order.js';
export { calculateOrderTotal } from './models/order.js';
export type {
  NotificationType,
  NotificationChannel,
  NotificationPriority,
  NotificationStatus,
  NotificationPayload,
  NotificationRecord,
  NotificationResult,
  CreateNotificationInput,
} from './models/notification.js';

// Utilities
export { Database, getDatabase, resetDatabase } from './utils/database.js';
export { Logger } from './utils/logger.js';
export { paginate } from './utils/pagination.js';
export type { PaginationResult } from './utils/pagination.js';

// Repositories
export { BaseRepository } from './repositories/base.repository.js';
export { UserRepository } from './repositories/user.repository.js';
export { OrderRepository } from './repositories/order.repository.js';

// Events
export { EventBus } from './events/event-bus.js';
export type {
  AppEvent,
  EventType,
  OrderCreatedEvent,
  OrderStatusChangedEvent,
  UserCreatedEvent,
  UserUpdatedEvent,
  NotificationSentEvent,
  NotificationFailedEvent,
} from './events/event-types.js';

// Adapters
export type { NotificationAdapter } from './adapters/notification.adapter.js';
export { EmailAdapter, defaultEmailConfig } from './adapters/email.adapter.js';
export type { EmailAdapterConfig } from './adapters/email.adapter.js';

// Services
export { UserService } from './services/user.service.js';
export { OrderService } from './services/order.service.js';
export { NotificationService } from './services/notification.service.js';

// Config
export { createConfig, defaultConfig } from './config/app.config.js';
export type { AppConfig } from './config/app.config.js';

import { describe, it, expect, beforeEach } from 'vitest';
import { EventBus } from '../../src/events/event-bus.js';
import {
  NotificationService,
  resetNotificationIdCounter,
} from '../../src/services/notification.service.js';
import { EmailAdapter } from '../../src/adapters/email.adapter.js';
import type {
  OrderCreatedEvent,
  OrderStatusChangedEvent,
  UserCreatedEvent,
  UserUpdatedEvent,
} from '../../src/events/event-types.js';
import type { NotificationAdapter } from '../../src/adapters/notification.adapter.js';
import type { NotificationPayload, NotificationResult } from '../../src/models/notification.js';

describe('NotificationService', () => {
  let eventBus: EventBus;
  let service: NotificationService;
  let emailAdapter: EmailAdapter;

  beforeEach(() => {
    eventBus = new EventBus();
    service = new NotificationService(eventBus);
    emailAdapter = new EmailAdapter({ stubMode: true });
    service.registerAdapter(emailAdapter);
    resetNotificationIdCounter();
  });

  describe('order:created handler', () => {
    it('should send notification on order created', async () => {
      const event: OrderCreatedEvent = {
        type: 'order:created',
        order: {
          id: 'order-1',
          userId: 'user-1',
          items: [
            { productId: 'p1', name: 'Widget', quantity: 2, unitPrice: 10 },
          ],
          total: 20,
          status: 'pending',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        user: {
          id: 'user-1',
          name: 'Alice',
          email: 'alice@example.com',
          role: 'member',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        timestamp: new Date(),
      };

      await eventBus.emit(event);

      const notifications = service.getNotifications();
      expect(notifications).toHaveLength(1);
      expect(notifications[0]?.recipient).toBe('alice@example.com');
      expect(notifications[0]?.subject).toContain('Order Confirmation');
      expect(notifications[0]?.body).toContain('Widget x2');
      expect(notifications[0]?.body).toContain('$20.00');
      expect(notifications[0]?.status).toBe('sent');
      expect(notifications[0]?.type).toBe('order_confirmation');
      expect(notifications[0]?.channel).toBe('email');
    });

    it('should include all items in notification body', async () => {
      const event: OrderCreatedEvent = {
        type: 'order:created',
        order: {
          id: 'order-1',
          userId: 'user-1',
          items: [
            { productId: 'p1', name: 'Widget', quantity: 2, unitPrice: 10 },
            { productId: 'p2', name: 'Gadget', quantity: 1, unitPrice: 25 },
          ],
          total: 45,
          status: 'pending',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        user: {
          id: 'user-1',
          name: 'Alice',
          email: 'alice@example.com',
          role: 'member',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        timestamp: new Date(),
      };

      await eventBus.emit(event);

      const notifications = service.getNotifications();
      expect(notifications[0]?.body).toContain('Widget x2');
      expect(notifications[0]?.body).toContain('Gadget x1');
    });
  });

  describe('order:status-changed handler (via EventBus)', () => {
    it('should send notification on status change via EventBus', async () => {
      const event: OrderStatusChangedEvent = {
        type: 'order:status-changed',
        order: {
          id: 'order-1',
          userId: 'user-1',
          items: [],
          total: 20,
          status: 'confirmed',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        previousStatus: 'pending',
        newStatus: 'confirmed',
        timestamp: new Date(),
      };

      await eventBus.emit(event);

      const notifications = service.getNotifications();
      expect(notifications).toHaveLength(1);
      expect(notifications[0]?.subject).toContain('Order Update');
      expect(notifications[0]?.body).toContain('pending');
      expect(notifications[0]?.body).toContain('confirmed');
      expect(notifications[0]?.type).toBe('order_status_update');
      expect(notifications[0]?.status).toBe('sent');
    });

    it('should set high priority for cancelled orders', async () => {
      const event: OrderStatusChangedEvent = {
        type: 'order:status-changed',
        order: {
          id: 'order-1',
          userId: 'user-1',
          items: [],
          total: 20,
          status: 'cancelled',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        previousStatus: 'pending',
        newStatus: 'cancelled',
        timestamp: new Date(),
      };

      await eventBus.emit(event);

      const notifications = service.getNotifications();
      expect(notifications[0]?.priority).toBe('high');
    });
  });

  describe('user event handlers', () => {
    it('should send welcome notification on user:created', async () => {
      const event: UserCreatedEvent = {
        type: 'user:created',
        user: {
          id: 'user-1',
          name: 'Bob',
          email: 'bob@example.com',
          role: 'member',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        timestamp: new Date(),
      };

      await eventBus.emit(event);

      const notifications = service.getNotifications();
      expect(notifications).toHaveLength(1);
      expect(notifications[0]?.recipient).toBe('bob@example.com');
      expect(notifications[0]?.subject).toContain('Welcome');
      expect(notifications[0]?.type).toBe('welcome');
    });

    it('should send update notification on user:updated', async () => {
      const event: UserUpdatedEvent = {
        type: 'user:updated',
        user: {
          id: 'user-1',
          name: 'Bob Updated',
          email: 'bob@example.com',
          role: 'admin',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        changes: ['name', 'role'],
        timestamp: new Date(),
      };

      await eventBus.emit(event);

      const notifications = service.getNotifications();
      expect(notifications).toHaveLength(1);
      expect(notifications[0]?.body).toContain('name');
      expect(notifications[0]?.body).toContain('role');
      expect(notifications[0]?.type).toBe('account_updated');
    });
  });

  describe('adapter management', () => {
    it('should register and list adapters', () => {
      const channels = service.getRegisteredChannels();
      expect(channels).toContain('email');
    });

    it('should unregister adapters', () => {
      const removed = service.unregisterAdapter('email');
      expect(removed).toBe(true);
      expect(service.getRegisteredChannels()).not.toContain('email');
    });

    it('should record failure when no adapter registered', async () => {
      service.unregisterAdapter('email');

      const event: OrderStatusChangedEvent = {
        type: 'order:status-changed',
        order: {
          id: 'order-1',
          userId: 'user-1',
          items: [],
          total: 20,
          status: 'confirmed',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        previousStatus: 'pending',
        newStatus: 'confirmed',
        timestamp: new Date(),
      };

      await eventBus.emit(event);

      const notifications = service.getNotifications();
      expect(notifications).toHaveLength(1);
      expect(notifications[0]?.status).toBe('failed');
      expect(notifications[0]?.failureReason).toContain('No adapter registered');
    });

    it('should handle adapter send failure gracefully', async () => {
      const failingAdapter: NotificationAdapter = {
        channel: 'email',
        async send(_payload: NotificationPayload): Promise<NotificationResult> {
          return {
            success: false,
            notificationId: '',
            channel: 'email',
            failureReason: 'SMTP connection refused',
          };
        },
      };
      service.registerAdapter(failingAdapter);

      const event: OrderStatusChangedEvent = {
        type: 'order:status-changed',
        order: {
          id: 'order-1',
          userId: 'user-1',
          items: [],
          total: 20,
          status: 'confirmed',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        previousStatus: 'pending',
        newStatus: 'confirmed',
        timestamp: new Date(),
      };

      await eventBus.emit(event);

      const notifications = service.getNotifications();
      expect(notifications[0]?.status).toBe('failed');
      expect(notifications[0]?.failureReason).toBe('SMTP connection refused');
    });
  });

  describe('notification management', () => {
    it('should count notifications', async () => {
      expect(service.getNotificationCount()).toBe(0);

      await eventBus.emit({
        type: 'order:status-changed',
        order: {
          id: 'order-1',
          userId: 'user-1',
          items: [],
          total: 20,
          status: 'confirmed',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        previousStatus: 'pending',
        newStatus: 'confirmed',
        timestamp: new Date(),
      } satisfies OrderStatusChangedEvent);

      expect(service.getNotificationCount()).toBe(1);
    });

    it('should filter by recipient', async () => {
      const event: OrderCreatedEvent = {
        type: 'order:created',
        order: {
          id: 'order-1',
          userId: 'user-1',
          items: [
            { productId: 'p1', name: 'Widget', quantity: 1, unitPrice: 10 },
          ],
          total: 10,
          status: 'pending',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        user: {
          id: 'user-1',
          name: 'Alice',
          email: 'alice@example.com',
          role: 'member',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        timestamp: new Date(),
      };

      await eventBus.emit(event);

      expect(service.getNotificationsForRecipient('alice@example.com')).toHaveLength(1);
      expect(service.getNotificationsForRecipient('bob@example.com')).toHaveLength(0);
    });

    it('should filter by status', async () => {
      await eventBus.emit({
        type: 'order:status-changed',
        order: {
          id: 'order-1',
          userId: 'user-1',
          items: [],
          total: 20,
          status: 'confirmed',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        previousStatus: 'pending',
        newStatus: 'confirmed',
        timestamp: new Date(),
      } satisfies OrderStatusChangedEvent);

      expect(service.getNotificationsByStatus('sent')).toHaveLength(1);
      expect(service.getNotificationsByStatus('failed')).toHaveLength(0);
    });

    it('should filter by type', async () => {
      await eventBus.emit({
        type: 'order:status-changed',
        order: {
          id: 'order-1',
          userId: 'user-1',
          items: [],
          total: 20,
          status: 'confirmed',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        previousStatus: 'pending',
        newStatus: 'confirmed',
        timestamp: new Date(),
      } satisfies OrderStatusChangedEvent);

      expect(service.getNotificationsByType('order_status_update')).toHaveLength(1);
      expect(service.getNotificationsByType('order_confirmation')).toHaveLength(0);
    });

    it('should clear notifications', async () => {
      await eventBus.emit({
        type: 'order:status-changed',
        order: {
          id: 'order-1',
          userId: 'user-1',
          items: [],
          total: 20,
          status: 'confirmed',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        previousStatus: 'pending',
        newStatus: 'confirmed',
        timestamp: new Date(),
      } satisfies OrderStatusChangedEvent);

      service.clearNotifications();
      expect(service.getNotificationCount()).toBe(0);
    });

    it('should generate sequential notification IDs', async () => {
      await eventBus.emit({
        type: 'order:status-changed',
        order: {
          id: 'order-1',
          userId: 'user-1',
          items: [],
          total: 20,
          status: 'confirmed',
