import { describe, it, expect, beforeEach } from 'vitest';
import { EmailAdapter } from '../../src/adapters/email.adapter.js';
import type { NotificationPayload } from '../../src/models/notification.js';

describe('EmailAdapter', () => {
  let adapter: EmailAdapter;

  const samplePayload: NotificationPayload = {
    type: 'order_confirmation',
    recipient: 'alice@example.com',
    subject: 'Order Confirmation: order-0001',
    body: 'Your order has been placed.',
    channel: 'email',
    priority: 'normal',
  };

  beforeEach(() => {
    adapter = new EmailAdapter({ stubMode: true });
  });

  describe('send', () => {
    it('should succeed in stub mode', async () => {
      const result = await adapter.send(samplePayload);

      expect(result.success).toBe(true);
      expect(result.channel).toBe('email');
    });

    it('should record sent emails in stub mode', async () => {
      await adapter.send(samplePayload);

      const sentEmails = adapter.getSentEmails();
      expect(sentEmails).toHaveLength(1);
      expect(sentEmails[0]?.to).toBe('alice@example.com');
      expect(sentEmails[0]?.subject).toBe('Order Confirmation: order-0001');
    });

    it('should fail in non-stub mode (no real SMTP configured)', async () => {
      const productionAdapter = new EmailAdapter({ stubMode: false });
      const result = await productionAdapter.send(samplePayload);

      expect(result.success).toBe(false);
      expect(result.failureReason).toBeDefined();
    });
  });

  describe('configuration', () => {
    it('should use default config when none provided', () => {
      const defaultAdapter = new EmailAdapter();
      const config = defaultAdapter.getConfig();

      expect(config.host).toBe('localhost');
      expect(config.port).toBe(587);
      expect(config.fromAddress).toBe('noreply@taskflow.dev');
      expect(config.stubMode).toBe(true);
    });

    it('should merge custom config with defaults', () => {
      const customAdapter = new EmailAdapter({
        host: 'smtp.example.com',
        fromAddress: 'app@example.com',
      });
      const config = customAdapter.getConfig();

      expect(config.host).toBe('smtp.example.com');
      expect(config.fromAddress).toBe('app@example.com');
      expect(config.port).toBe(587); // default preserved
    });
  });

  describe('channel property', () => {
    it('should report email as its channel', () => {
      expect(adapter.channel).toBe('email');
    });
  });

  describe('clearSentEmails', () => {
    it('should clear sent email records', async () => {
      await adapter.send(samplePayload);
      expect(adapter.getSentEmails()).toHaveLength(1);

      adapter.clearSentEmails();
      expect(adapter.getSentEmails()).toHaveLength(0);
    });
  });
});

